// Extract the classification from either:
//  (a) the raw Anthropic Messages API response (`LLM Classification` node),
//      where the JSON classification is embedded as a string in
//      content[0].text, or
//  (b) the feedback-service response (`HTTP Request1` -> POST
//      /classify-feedback), which already returns a structured
//      `classification` object.
// Then compute the MINIMUM label confidence (not average) so one uncertain
// label forces the whole feedback into human review.
//
// feedback_id / course_id / raw_feedback are pulled from `Edit Fields`
// (the shared node before the preprocessing/classification branches) via
// item-linking, since neither response body above carries those fields
// through on its own.

return items.map((item, i) => {
  const res = item.json;
  let parsed;
  let rawLlmResponse = '';
  let llmModel = 'claude-sonnet-4-6';

  if (res.content?.[0]?.text) {
    // (a) Raw Anthropic API response
    rawLlmResponse = res.content[0].text;
    llmModel = res.model || llmModel;
    try {
      parsed = JSON.parse(rawLlmResponse);
    } catch (e) {
      parsed = { actionable: false, summary: '', labels: [] };
    }
  } else if (res.classification) {
    // (b) feedback-service /classify-feedback response
    parsed = res.classification;
    rawLlmResponse = JSON.stringify(res.classification);
    llmModel = 'feedback-service';
  } else {
    parsed = { actionable: false, summary: '', labels: [] };
  }

  const confidences = (parsed.labels || []).map(l => l.confidence ?? 0);
  const minConfidence = confidences.length ? Math.min(...confidences) : 0;

  const source = $('Edit Fields').itemMatching(i).json;

  return {
    json: {
      feedback_id: source.feedback_id,
      course_id: source.course_id,
      actionable: parsed.actionable ?? false,
      summary: parsed.summary || '',
      labels: parsed.labels || [],
      llm_model: llmModel,
      min_confidence: minConfidence,
      review_required: minConfidence < 0.70,
      raw_llm_response: rawLlmResponse,
      raw_feedback: source.raw_feedback
    }
  };
});

// One n8n item per LABEL (feedback_labels is one row per label).
const OWNER_MAP = {
  Content: 'Course Lead',
  Tutor: 'Course Lead',
  Tech: 'QA Lead',
  Admin: 'Operations Lead'
};

const out = [];
for (const item of items) {
  const f = item.json;
  for (const label of (f.labels || [])) {
    const prefix = (label.label || '').split('|')[0];
    out.push({
      json: {
        feedback_id: f.feedback_id,
        course_id: f.course_id,
        label: label.label,
        sentiment: label.sentiment,
        severity: label.severity,
        confidence: label.confidence,
        owner_role: OWNER_MAP[prefix] || 'Course Lead',
        actionable: f.actionable
      }
    });
  }
}
return out;

